import{_ as a,c as t,o as e,a1 as s}from"./chunks/framework.CQ_MtUmI.js";const Q=JSON.parse('{"title":"NapCatQQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1717298516000}'),i={name:"zh-CN/guide/getting-started.md"},p=s(`<h1 id="napcatqq" tabindex="-1">NapCatQQ <a class="header-anchor" href="#napcatqq" aria-label="Permalink to &quot;NapCatQQ&quot;">​</a></h1><p>NapCatQQ 是基于 PC NTQQ 客户端本体实现的 QQ Bot 框架，稳定安全，快速部署。</p><h2 id="napcatqq-的优势" tabindex="-1">NapCatQQ 的优势 <a class="header-anchor" href="#napcatqq-的优势" aria-label="Permalink to &quot;NapCatQQ 的优势&quot;">​</a></h2><ul><li><p>不需要图形环境，Linux表现优异，与现有Hook框架有着本质区别，在性能与内存占用方面远远优于基于Hook的框架。</p></li><li><p>配置简单，支持浏览器远程进入进行配置，简单轻松即可完成配置。</p></li><li><p>NTQQ功能适配快速，更新持续跟进QQ最新版。</p></li></ul><h2 id="启动前需要了解的三两事-你给我好好读三遍" tabindex="-1">启动前需要了解的三两事 (！你给我好好读三遍) <a class="header-anchor" href="#启动前需要了解的三两事-你给我好好读三遍" aria-label="Permalink to &quot;启动前需要了解的三两事 (！你给我好好读三遍)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li><p>NapCat 是基于 PC NTQQ 客户端本体实现的 QQ Bot 框架，所以说需要提前安装好和 <strong>NapCatQQ 对应的 QQ 版本</strong>才能运行 NapCat。</p></li><li><p>NapCat 在线时，你不能使用 PC QQ 客户端实现人机合一，但是可以选择同步登录移动客户端，如果想要在 PC 上人机合一请使用 <a href="https://github.com/LLOneBot/LLOneBot" target="_blank" rel="noreferrer">LLOneBot</a></p></li><li><p>NapCat 不同于协议实现，是基于 QQ 客户端，QQ 客户端上干不了的事，NapCat &gt;_&lt; 当然也是不行的!</p></li></ul></div><h2 id="安装-qq" tabindex="-1">安装 QQ <a class="header-anchor" href="#安装-qq" aria-label="Permalink to &quot;安装 QQ&quot;">​</a></h2><p>NapCatQQ v1.4.7：</p><p><a href="https://dldir1.qq.com/qqfile/qq/QQNT/Windows/QQ_9.9.10_240523_x64_01.exe" target="_blank" rel="noreferrer">Windows 9.9.10-24108</a> | <a href="https://dldir1.qq.com/qqfile/qq/QQNT/8b4fdf81/linuxqq_3.2.7-23361_amd64.deb" target="_blank" rel="noreferrer">Linux 3.2.7-23361</a></p><p>Linux 无需桌面安装 NTQQ，具体命令如下：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libgbm1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libasound2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./qq.deb</span></span></code></pre></div><p>更多版本请查看<a href="./version">版本更新记录</a>。</p><h2 id="下载-napcatqq" tabindex="-1">下载 NapCatQQ <a class="header-anchor" href="#下载-napcatqq" aria-label="Permalink to &quot;下载 NapCatQQ&quot;">​</a></h2><p>下载地址: <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">https://github.com/NapNeko/NapCatQQ/releases</a></p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>为了避免二次启动，可以事先配置好 NapCat 的基础设置，见 <a href="./config">配置 NapCat</a>。</p><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h2><details class="details custom-block"><summary>Windows</summary><p>我们安装好对应版本 QQ 后，大多数情况下，只需要解压 NapCat，并将其放到你想的的任何地方。但注意，路径不能包含空格。然后，双击 <code>napcat.bat</code> 就可以运行啦！</p><p>等等! 如果你出现乱码可以尝试双击 <code>napcat-utf8.bat</code> 启动。</p><p>如果上面的方法还是不行，可以尝试用 Powershell 启动：</p><p>启动 PowerShell，运行 <code>powershell ./napcat.ps1</code> 或者 <code>napcat.bat</code>，如果出现乱码，可以尝试运行 <code>napcat-utf8.ps1</code> 或 <code>napcat-utf8.bat</code>。</p><p>如果运行不了，可以尝试 <code>powershell.exe -ExecutionPolicy Bypass -File &quot;.\\napcat.ps1&quot;</code>。</p><p><strong>推荐直接点击 bat 运行，因为 PowerShell 自身会占用 20 MB 左右的内存。</strong></p></details><details class="details custom-block"><summary>Linux一键脚本</summary><p>墙裂推荐！</p><p><code>curl -o napcat.sh https://fastly.jsdelivr.net/gh/NapNeko/NapCat-Installer@master/script/install.sh &amp;&amp; sudo bash napcat.sh</code></p></details><details class="details custom-block"><summary><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">Linux Docker</a></summary></details><details class="details custom-block"><summary>Linux 非 Docker</summary><p>终端运行</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u+x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./napcat.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./napcat.sh</span></span></code></pre></div><p>请勿用<code>sh napcat.sh</code>启动，可能会出现路径问题而无法启动。</p></details><details class="details custom-block"><summary>快速登录（无需扫码）</summary><p>如果你已经成功登录过官方 QQ 或者 NapCatQQ，可以加参数<code> -q &lt;你的QQ&gt;</code> 进行快速登录而无需扫码，如 <code>napcat.bat -q 1234567</code> 或者 <code>napcat.sh -q 1234567</code>。</p></details><h3 id="启动之后" tabindex="-1">启动之后 <a class="header-anchor" href="#启动之后" aria-label="Permalink to &quot;启动之后&quot;">​</a></h3><p>恭喜你，如果看到这里，你已经成功启动了 NapCat，可以尝试阅读下面的进阶说明！</p><p><a href="/zh-CN/guide/config">如何进行 NapCat 的基础设置</a></p><p><a href="/zh-CN/guide/faq">如何配置 NapCat 的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="/zh-CN/guide/faq">遇到 NapCat 崩溃问题如何解决</a></p>`,27),l=[p];function o(n,r,h,d,c,u){return e(),t("div",null,l)}const g=a(i,[["render",o]]);export{Q as __pageData,g as default};
